<?php namespace App\Repositories\Asset;use App\Repositories\BaseRepository;use App\Models\Asset\AssetDepreciation;use Illuminate\Database\Eloquent\Collection;class AssetDepreciationRepository extends BaseRepository{    public function __construct(AssetDepreciation $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByAsset(int $assetId): Collection    {        return $this->findByField('asset_id', $assetId);    }    public function findByMethod(string $method): Collection    {        return $this->findByField('depreciation_method', $method);    }    public function getByYear(int $year): Collection    {        return $this->findByField('year', $year);    }    public function getByFiscalYear(int $year): Collection    {        return $this->findByField('fiscal_year', $year);    }    public function getCurrentDepreciation(int $assetId): ?AssetDepreciation    {        return $this->query()->where('asset_id', $assetId)->orderBy('year', 'desc')->orderBy('period', 'desc')->first();    }    public function getDepreciationSchedule(int $assetId): Collection    {        return $this->query()->where('asset_id', $assetId)->orderBy('year', 'asc')->orderBy('period', 'asc')->get();    }    public function getTotalDepreciation(int $assetId): float    {        return $this->query()->where('asset_id', $assetId)->sum('depreciation_amount');    }    public function getByAmountRange(float $min, float $max): Collection    {        return $this->query()->whereBetween('depreciation_amount', [$min, $max])->get();    }    public function recordDepreciation(array $data): AssetDepreciation    {        return $this->create($data);    }    public function getByAssetAndYear(int $assetId, int $year): ?AssetDepreciation    {        return $this->query()->where('asset_id', $assetId)->where('year', $year)->first();    }    public function getCurrentBookValue(int $assetId): float    {        $totalDepreciation = $this->getTotalDepreciation($assetId);        $asset = $this->model->newQuery()->find($assetId);        return $asset ? ($asset->purchase_cost - $totalDepreciation) : 0;    }}